import React from "react";
import { Link, useLocation } from "react-router-dom";
import "./BookingConfirmation.css";

export default function BookingConfirmation() {
  const location = useLocation();

  // ✅ Read the "name" from the URL (e.g., ?name=Luxury%20Beach%20Villa)
  const queryParams = new URLSearchParams(location.search);
  const stayName = queryParams.get("name");

  return (
    <div className="booking-container">
      <div className="confirmation-card">
        <h1>🎉 Booking Confirmed!</h1>

        {stayName ? (
          <p>
            Your booking for <strong>{stayName}</strong> has been confirmed. 🏡
          </p>
        ) : (
          <p>Your stay has been successfully booked!</p>
        )}

        <p>Thank you for choosing our Airbnb Clone.</p>

        {/* ✅ Link back to home */}
        <Link to="/">
          <button className="back-home-btn">Back to Home</button>
        </Link>
      </div>
    </div>
  );
}
